/**
 * ics.js - GroupSync Modified Version (2026)
 * แก้ไขเพื่อรองรับ iOS/Android โดยเฉพาะ
 */
var ics = function() {
    "use strict";
    if ("undefined" == typeof RegExp) return;

    var e = {
        Separator: "\r\n",
        // 1. เพิ่ม METHOD:PUBLISH (จุดตายที่ทำให้ iPhone ไม่ขึ้นปุ่ม Add)
        Command: "BEGIN:VCALENDAR\r\nVERSION:2.0\r\nMETHOD:PUBLISH\r\nPRODID:-//GroupSync//NONSGML v1.0//EN\r\n",
        End: "END:VCALENDAR",
        Events: [],
        Calendar: function() {
            return this.Command + this.Events.join("") + this.End;
        },
        addEvent: function(subject, description, location, begin, end) {
            if (!subject || !begin || !end) return false;

            var a = new Date(begin),
                o = new Date(end);

            // 2. ฟังก์ชันจัด Format วันที่ (ตัดขีด - และจุด : ออกให้หมดตามกฎ iOS)
            var format = function(d) {
                return d.getFullYear() + 
                    ("00" + (d.getMonth() + 1)).slice(-2) + 
                    ("00" + d.getDate()).slice(-2) + "T" + 
                    ("00" + d.getHours()).slice(-2) + 
                    ("00" + d.getMinutes()).slice(-2) + 
                    ("00" + d.getSeconds()).slice(-2);
            };

            var s = format(a),
                c = format(o);

            // 3. ปรับโครงสร้าง VEVENT ใหม่ (ลบ ;VALUE=DATE-TIME ออก)
            var u = [
                "BEGIN:VEVENT",
                "UID:" + Date.now() + "@groupsync",
                "DTSTAMP:" + s + "Z",
                "DTSTART:" + s,
                "DTEND:" + c,
                "SUMMARY:" + subject,
                "DESCRIPTION:" + description,
                "LOCATION:" + location,
                "END:VEVENT",
                ""
            ].join(this.Separator);

            this.Events.push(u);
            return u;
        },
        download: function(filename) {
            if (this.Events.length < 1) return false;
            filename = (filename || "calendar") + ".ics";
            var content = this.Calendar();
            
            // 4. ใช้ Blob Type ที่ถูกต้องสำหรับ Mobile
            var n = new Blob([content], { type: "text/calendar;charset=utf-8" });
            saveAs(n, filename);
            return content;
        }
    };
    return e;
};

// ฟังก์ชันเสริมสำหรับสั่งดาวน์โหลด (แทนที่ตัวเดิมที่อาจจะพังใน Mobile)
if ("undefined" == typeof saveAs) {
    var saveAs = function(blob, filename) {
        var url = URL.createObjectURL(blob);
        var a = document.createElement("a");
        a.href = url;
        a.download = filename;
        a.style.display = "none";
        document.body.appendChild(a);
        a.click();
        setTimeout(function() {
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }, 100);
    };
}